import { jest } from '@jest/globals';
import AgentOrchestrator from '../src/agent/AgentOrchestrator.js';
import ToolRegistry from '../src/tools/ToolRegistry.js';
import ContextManager from '../src/context/ContextManager.js';

// Mock MistralClient for integration tests
const createMockMistralClient = () => ({
  registerTools: jest.fn(),
  sendWithTools: jest.fn(),
});

// Mock FileSystemManager
const createMockFileSystemManager = () => ({
  readFile: jest.fn(),
  writeFile: jest.fn(),
  listDirectory: jest.fn(),
});

// Mock SearchEngine
const createMockSearchEngine = () => ({
  search: jest.fn(),
});

describe('Agent Integration Tests', () => {
  let mistralClient;
  let toolRegistry;
  let contextManager;
  let orchestrator;
  let fileSystemManager;
  let searchEngine;

  beforeEach(() => {
    jest.clearAllMocks();
    
    mistralClient = createMockMistralClient();
    fileSystemManager = createMockFileSystemManager();
    searchEngine = createMockSearchEngine();
    
    toolRegistry = new ToolRegistry(fileSystemManager, searchEngine);
    contextManager = new ContextManager();
    orchestrator = new AgentOrchestrator(mistralClient, toolRegistry);

    // Register some basic tools
    toolRegistry.registerTool('read_file', {
      description: 'Read a file',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string' }
        },
        required: ['path']
      }
    }, async (params) => {
      return await fileSystemManager.readFile(params.path);
    });

    toolRegistry.registerTool('write_file', {
      description: 'Write a file',
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          content: { type: 'string' }
        },
        required: ['path', 'content']
      }
    }, async (params) => {
      return await fileSystemManager.writeFile(params.path, params.content);
    });

    toolRegistry.registerTool('search_code', {
      description: 'Search code',
      parameters: {
        type: 'object',
        properties: {
          query: { type: 'string' }
        },
        required: ['query']
      }
    }, async (params) => {
      return await searchEngine.search(params.query);
    });
  });

  describe('End-to-End Agent Workflow', () => {
    it('should handle a complete file reading workflow', async () => {
      // Setup: AI wants to read a file and then respond
      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_read_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "package.json"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const finalResponse = {
        content: 'I can see this is a Node.js project with Jest for testing.',
        role: 'assistant',
        finishReason: 'stop',
      };

      mistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(finalResponse);

      fileSystemManager.readFile.mockResolvedValue('{"name": "codestral", "devDependencies": {"jest": "^29.0.0"}}');

      // Execute
      const result = await orchestrator.processMessage(
        'What kind of project is this?',
        contextManager
      );

      // Verify
      expect(result.content).toBe('I can see this is a Node.js project with Jest for testing.');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);
      
      expect(fileSystemManager.readFile).toHaveBeenCalledWith('package.json');
      expect(mistralClient.registerTools).toHaveBeenCalledWith(toolRegistry.getToolDefinitions());
      
      // Check context was updated
      const messages = contextManager.getMessages();
      expect(messages).toHaveLength(3); // user message + tool result + final response
      expect(messages[0].role).toBe('user');
      expect(messages[1].role).toBe('assistant');
      expect(messages[2].role).toBe('assistant');
    });

    it('should handle multi-step workflow with search and file operations', async () => {
      // Scenario: Find TODO comments and create a summary file
      
      // Step 1: AI searches for TODO comments
      const searchResponse = {
        toolCalls: [
          {
            id: 'call_search_1',
            function: {
              name: 'search_code',
              arguments: '{"query": "TODO"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      // Step 2: AI reads one of the files to get context
      const readResponse = {
        toolCalls: [
          {
            id: 'call_read_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "src/main.js"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      // Step 3: AI writes summary file
      const writeResponse = {
        toolCalls: [
          {
            id: 'call_write_1',
            function: {
              name: 'write_file',
              arguments: '{"path": "TODO_SUMMARY.md", "content": "# TODO Summary\\n\\n- Fix authentication bug in main.js\\n"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      // Step 4: Final response
      const finalResponse = {
        content: 'I\'ve created TODO_SUMMARY.md with all the TODO items I found.',
        role: 'assistant',
        finishReason: 'stop',
      };

      mistralClient.sendWithTools
        .mockResolvedValueOnce(searchResponse)
        .mockResolvedValueOnce(readResponse)
        .mockResolvedValueOnce(writeResponse)
        .mockResolvedValueOnce(finalResponse);

      // Mock tool responses
      searchEngine.search.mockResolvedValue([
        { filePath: 'src/main.js', lineNumber: 42, line: '// TODO: Fix authentication bug' }
      ]);
      
      fileSystemManager.readFile.mockResolvedValue('function authenticate() {\n  // TODO: Fix authentication bug\n  return false;\n}');
      fileSystemManager.writeFile.mockResolvedValue('File written successfully');

      // Execute
      const result = await orchestrator.processMessage(
        'Find all TODO comments and create a summary file',
        contextManager
      );

      // Verify
      expect(result.content).toBe('I\'ve created TODO_SUMMARY.md with all the TODO items I found.');
      expect(result.iterations).toBe(4);
      expect(result.toolCallsUsed).toBe(3);

      // Verify tool calls
      expect(searchEngine.search).toHaveBeenCalledWith('TODO');
      expect(fileSystemManager.readFile).toHaveBeenCalledWith('src/main.js');
      expect(fileSystemManager.writeFile).toHaveBeenCalledWith(
        'TODO_SUMMARY.md',
        '# TODO Summary\n\n- Fix authentication bug in main.js\n'
      );

      // Verify context
      const messages = contextManager.getMessages();
      expect(messages).toHaveLength(5); // user + 3 tool results + final response
    });

    it('should handle tool execution failures gracefully', async () => {
      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_read_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "nonexistent.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const recoveryResponse = {
        content: 'The file doesn\'t exist. Would you like me to create it?',
        role: 'assistant',
        finishReason: 'stop',
      };

      mistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(recoveryResponse);

      fileSystemManager.readFile.mockRejectedValue(new Error('File not found'));

      const result = await orchestrator.processMessage(
        'Read the config file',
        contextManager
      );

      expect(result.content).toBe('The file doesn\'t exist. Would you like me to create it?');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);

      // Verify error was handled
      const toolStats = orchestrator.getToolCallStats();
      expect(toolStats.failedCalls).toBe(1);
      expect(toolStats.toolUsage.read_file.failures).toBe(1);
    });

    it('should track tool call statistics correctly', async () => {
      // Multiple tool calls with mixed success/failure
      const responses = [
        {
          toolCalls: [
            {
              id: 'call_1',
              function: { name: 'read_file', arguments: '{"path": "file1.txt"}' }
            }
          ],
          role: 'assistant',
          finishReason: 'tool_calls',
        },
        {
          toolCalls: [
            {
              id: 'call_2',
              function: { name: 'read_file', arguments: '{"path": "nonexistent.txt"}' }
            }
          ],
          role: 'assistant',
          finishReason: 'tool_calls',
        },
        {
          toolCalls: [
            {
              id: 'call_3',
              function: { name: 'write_file', arguments: '{"path": "output.txt", "content": "Hello"}' }
            }
          ],
          role: 'assistant',
          finishReason: 'tool_calls',
        },
        {
          content: 'All done!',
          role: 'assistant',
          finishReason: 'stop',
        }
      ];

      mistralClient.sendWithTools
        .mockResolvedValueOnce(responses[0])
        .mockResolvedValueOnce(responses[1])
        .mockResolvedValueOnce(responses[2])
        .mockResolvedValueOnce(responses[3]);

      fileSystemManager.readFile
        .mockResolvedValueOnce('File content')
        .mockRejectedValueOnce(new Error('File not found'));
      
      fileSystemManager.writeFile.mockResolvedValue('Success');

      await orchestrator.processMessage('Process some files', contextManager);

      const stats = orchestrator.getToolCallStats();
      expect(stats.totalCalls).toBe(3);
      expect(stats.successfulCalls).toBe(2);
      expect(stats.failedCalls).toBe(1);
      expect(stats.toolUsage.read_file.count).toBe(2);
      expect(stats.toolUsage.read_file.successes).toBe(1);
      expect(stats.toolUsage.read_file.failures).toBe(1);
      expect(stats.toolUsage.write_file.count).toBe(1);
      expect(stats.toolUsage.write_file.successes).toBe(1);
    });

    it('should handle callback functions during execution', async () => {
      const onToolCall = jest.fn();
      const onToolResult = jest.fn();
      const onResponse = jest.fn();

      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "test.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const finalResponse = {
        content: 'File processed successfully',
        role: 'assistant',
        finishReason: 'stop',
      };

      mistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(finalResponse);

      fileSystemManager.readFile.mockResolvedValue('File content');

      await orchestrator.processMessage(
        'Read the test file',
        contextManager,
        {
          onToolCall,
          onToolResult,
          onResponse
        }
      );

      // Verify callbacks were called
      expect(onToolCall).toHaveBeenCalledWith('read_file', { path: 'test.txt' }, expect.any(String));
      expect(onToolResult).toHaveBeenCalledWith(expect.objectContaining({
        success: true,
        result: 'File content'
      }));
      expect(onResponse).toHaveBeenCalledWith('File processed successfully', finalResponse);
    });

    it('should maintain conversation context across multiple interactions', async () => {
      // First interaction
      mistralClient.sendWithTools.mockResolvedValueOnce({
        content: 'Hello! How can I help you?',
        role: 'assistant',
        finishReason: 'stop',
      });

      await orchestrator.processMessage('Hello', contextManager);

      // Second interaction with tool use
      mistralClient.sendWithTools
        .mockResolvedValueOnce({
          toolCalls: [
            {
              id: 'call_1',
              function: { name: 'read_file', arguments: '{"path": "config.json"}' }
            }
          ],
          role: 'assistant',
          finishReason: 'tool_calls',
        })
        .mockResolvedValueOnce({
          content: 'The config shows debug mode is enabled.',
          role: 'assistant',
          finishReason: 'stop',
        });

      fileSystemManager.readFile.mockResolvedValue('{"debug": true}');

      await orchestrator.processMessage('Check the config file', contextManager);

      // Verify context contains all messages
      const messages = contextManager.getMessages();
      expect(messages).toHaveLength(5); // 2 user + 2 assistant + 1 tool result
      expect(messages[0].content).toBe('Hello');
      expect(messages[1].content).toBe('Hello! How can I help you?');
      expect(messages[2].content).toBe('Check the config file');
      expect(messages[3].content).toContain('Tool execution results');
      expect(messages[4].content).toBe('The config shows debug mode is enabled.');
    });
  });

  describe('Error Recovery and Resilience', () => {
    it('should recover from network errors and continue processing', async () => {
      // First call fails, second succeeds
      mistralClient.sendWithTools
        .mockRejectedValueOnce(new Error('Network timeout'))
        .mockResolvedValueOnce({
          content: 'Sorry for the delay, how can I help?',
          role: 'assistant',
          finishReason: 'stop',
        });

      const result = await orchestrator.processMessage('Hello', contextManager);

      // Should eventually succeed after retries
      expect(result.content).toBe('Sorry for the delay, how can I help?');
      expect(result.iterations).toBe(2); // Failed once, then succeeded
    });

    it('should handle malformed tool calls gracefully', async () => {
      const malformedResponse = {
        toolCalls: [
          {
            id: 'call_1',
            function: {
              name: 'read_file',
              arguments: 'invalid json'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const recoveryResponse = {
        content: 'I had trouble with that request. Let me try a different approach.',
        role: 'assistant',
        finishReason: 'stop',
      };

      mistralClient.sendWithTools
        .mockResolvedValueOnce(malformedResponse)
        .mockResolvedValueOnce(recoveryResponse);

      const result = await orchestrator.processMessage('Read a file', contextManager);

      expect(result.content).toBe('I had trouble with that request. Let me try a different approach.');
      
      // Verify the malformed tool call was handled (but counted as a failed tool call)
      expect(result.toolCallsUsed).toBe(1); // One tool call attempted (even though it failed)
      expect(result.iterations).toBe(2); // Two iterations (malformed call + recovery)
    });
  });
});